def is_luhn_valid(card_number):
    cleaned_number = ''.join(filter(str.isdigit, card_number))

    if not cleaned_number:
        return False

    total_sum = 0
    num_digits = len(cleaned_number)

    for i in range(num_digits - 1, -1, -1):
        digit = int(cleaned_number[i])

        # Every second digit from the right (0-indexed from right is 1, 3, 5...)
        if (num_digits - 1 - i) % 2 == 1:
            digit *= 2
            if digit > 9:
                digit -= 9

        total_sum += digit

    return total_sum % 10 == 0
